import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.DjxoKHTk.js";const u=JSON.parse('{"title":"韓式泡菜鍋 — 孫榮Kai主廚正宗食譜","description":"五星主廚孫榮Kai教你用台灣買得到的食材，煮出正宗韓式泡菜鍋！公開泡菜鍋底的真相與專業技巧。","frontmatter":{"title":"韓式泡菜鍋 — 孫榮Kai主廚正宗食譜","description":"五星主廚孫榮Kai教你用台灣買得到的食材，煮出正宗韓式泡菜鍋！公開泡菜鍋底的真相與專業技巧。"},"headers":[],"relativePath":"韓式/韓式泡菜鍋_孫榮Kai.md","filePath":"韓式/韓式泡菜鍋_孫榮Kai.md","lastUpdated":1781138667000}'),n={name:"韓式/韓式泡菜鍋_孫榮Kai.md"};function d(l,t,i,s,h,g){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="韓式泡菜鍋-🥘" tabindex="-1">韓式泡菜鍋 🥘 <a class="header-anchor" href="#韓式泡菜鍋-🥘" aria-label="Permalink to &quot;韓式泡菜鍋 🥘&quot;">​</a></h1><p><strong>來源：</strong> <a href="https://youtu.be/7_K3_ByiA-s" target="_blank" rel="noreferrer">YouTube - 孫榮Kai Son</a><strong>頻道/作者：</strong> 孫榮Kai Son <strong>分享日期：</strong> 2026/06/09</p><hr><blockquote><p>五星主廚孫榮Kai不藏私公開！從泡菜挑選、鍋底製作到最終調味，完整傳授正宗韓式泡菜鍋的專業技巧。用台灣買得到的食材，在家也能煮出餐廳級美味！</p></blockquote><hr><h2 id="📝-食材" tabindex="-1">📝 食材 <a class="header-anchor" href="#📝-食材" aria-label="Permalink to &quot;📝 食材&quot;">​</a></h2><table tabindex="0"><thead><tr><th>食材</th><th style="text-align:center;">份量</th><th>備註</th></tr></thead><tbody><tr><td>🥬 <strong>韓式泡菜</strong></td><td style="text-align:center;">適量</td><td>選用熟成較久的泡菜（酸味足夠），煮鍋風味更佳</td></tr><tr><td>🥩 <strong>豬肩胛肉/梅花肉</strong></td><td style="text-align:center;">200~300g</td><td>推薦豬肩胛肉或梅花肉，適合燉煮</td></tr><tr><td>🧅 <strong>洋蔥</strong></td><td style="text-align:center;">1/2 顆</td><td>切絲</td></tr><tr><td>🌿 <strong>大蔥</strong></td><td style="text-align:center;">2~3 根</td><td>斜切段</td></tr><tr><td>🌶️ <strong>辣椒</strong></td><td style="text-align:center;">適量</td><td>依個人口味調整</td></tr><tr><td>🫘 <strong>豆腐</strong></td><td style="text-align:center;">1 盒</td><td>切塊</td></tr><tr><td>🧄 <strong>蒜末</strong></td><td style="text-align:center;">1 大匙</td><td>最後才加，保留香氣</td></tr><tr><td>🍅 <strong>番茄醬</strong></td><td style="text-align:center;">1 大匙</td><td>⭐ 主廚秘訣！取代糖/醋，平衡酸度與提鮮</td></tr><tr><td>🧂 <strong>味醂</strong></td><td style="text-align:center;">1 大匙</td><td>最終調味</td></tr><tr><td>🧂 <strong>白醋</strong></td><td style="text-align:center;">少許</td><td>最終調味</td></tr><tr><td>🐟 <strong>魚露</strong></td><td style="text-align:center;">1 小匙</td><td>最終調味，打造道地韓式風味</td></tr><tr><td>💧 <strong>水</strong></td><td style="text-align:center;">適量</td><td>分兩次加入（關鍵！）</td></tr></tbody></table><hr><h2 id="👨‍🍳-做法" tabindex="-1">👨‍🍳 做法 <a class="header-anchor" href="#👨‍🍳-做法" aria-label="Permalink to &quot;👨‍🍳 做法&quot;">​</a></h2><h3 id="步驟-1-泡菜挑選-🥬" tabindex="-1">步驟 1：泡菜挑選 🥬 <a class="header-anchor" href="#步驟-1-泡菜挑選-🥬" aria-label="Permalink to &quot;步驟 1：泡菜挑選 🥬&quot;">​</a></h3><p>選用<strong>熟成較久、酸味足夠</strong>的泡菜來煮鍋。太新鮮的泡菜風味不足，煮出來的湯頭不夠濃郁。</p><h3 id="步驟-2-蔬菜備料-🔪" tabindex="-1">步驟 2：蔬菜備料 🔪 <a class="header-anchor" href="#步驟-2-蔬菜備料-🔪" aria-label="Permalink to &quot;步驟 2：蔬菜備料 🔪&quot;">​</a></h3><p>洋蔥切絲、大蔥斜切段、辣椒切片備用。豆腐切塊備用。</p><h3 id="步驟-3-肉品處理與切法-🥓" tabindex="-1">步驟 3：肉品處理與切法 🥓 <a class="header-anchor" href="#步驟-3-肉品處理與切法-🥓" aria-label="Permalink to &quot;步驟 3：肉品處理與切法 🥓&quot;">​</a></h3><p>推薦使用<strong>豬肩胛肉或梅花肉</strong>，切成適合燉煮的厚度。用泡菜汁稍微醃肉，讓肉吸收泡菜的風味。</p><h3 id="步驟-4-炒出香氣-🔥" tabindex="-1">步驟 4：炒出香氣 🔥 <a class="header-anchor" href="#步驟-4-炒出香氣-🔥" aria-label="Permalink to &quot;步驟 4：炒出香氣 🔥&quot;">​</a></h3><ol><li>鍋中加少許油，放入醃好的豬肉<strong>先炒出香氣</strong></li><li>加入洋蔥絲、大蔥段拌炒</li><li>加入泡菜繼續翻炒，讓所有食材充分融合</li></ol><h3 id="步驟-5-主廚秘訣-—-番茄醬提鮮-🍅" tabindex="-1">步驟 5：主廚秘訣 — 番茄醬提鮮 🍅 <a class="header-anchor" href="#步驟-5-主廚秘訣-—-番茄醬提鮮-🍅" aria-label="Permalink to &quot;步驟 5：主廚秘訣 — 番茄醬提鮮 🍅&quot;">​</a></h3><blockquote><p>⭐ <strong>不加糖或醋</strong>，改用<strong>番茄醬</strong>來平衡泡菜的酸度並提鮮！ 這是孫榮主廚的獨門撇步，讓湯頭更有層次。</p></blockquote><p>加入 1 大匙番茄醬，與鍋中食材拌炒均勻。</p><h3 id="步驟-6-分次加水-—-湯頭濃郁的關鍵-💧" tabindex="-1">步驟 6：分次加水 — 湯頭濃郁的關鍵 💧 <a class="header-anchor" href="#步驟-6-分次加水-—-湯頭濃郁的關鍵-💧" aria-label="Permalink to &quot;步驟 6：分次加水 — 湯頭濃郁的關鍵 💧&quot;">​</a></h3><blockquote><p>⭐ <strong>水不要一次加完！</strong> 分兩次加水是湯頭濃郁的秘訣。</p></blockquote><ol><li><strong>第一次加水</strong>：稍微蓋過食材，煮出濃郁底味</li><li>煮滾後讓湯汁稍微收乾，味道更濃縮</li><li><strong>第二次加水</strong>：補足所需湯量，調整濃度</li></ol><h3 id="步驟-7-加入豆腐-🫘" tabindex="-1">步驟 7：加入豆腐 🫘 <a class="header-anchor" href="#步驟-7-加入豆腐-🫘" aria-label="Permalink to &quot;步驟 7：加入豆腐 🫘&quot;">​</a></h3><p>放入切好的豆腐塊，輕輕攪拌，讓豆腐吸收湯汁。</p><h3 id="步驟-8-最終調味-🧂" tabindex="-1">步驟 8：最終調味 🧂 <a class="header-anchor" href="#步驟-8-最終調味-🧂" aria-label="Permalink to &quot;步驟 8：最終調味 🧂&quot;">​</a></h3><p>加入以下調味料進行微調：</p><ul><li><strong>味醂</strong> 1 大匙 — 增加甘甜與光澤</li><li><strong>白醋</strong> 少許 — 提升酸度層次</li><li><strong>魚露</strong> 1 小匙 — 打造道地韓式風味</li></ul><h3 id="步驟-9-完美收尾-🧄" tabindex="-1">步驟 9：完美收尾 🧄 <a class="header-anchor" href="#步驟-9-完美收尾-🧄" aria-label="Permalink to &quot;步驟 9：完美收尾 🧄&quot;">​</a></h3><blockquote><p>⭐ <strong>最後才加蒜末！</strong> 這是保留辛香氣息的關鍵。</p></blockquote><p>關火前加入蒜末，稍微攪拌即可。這樣蒜的香氣最鮮明，不會因久煮而流失。</p><hr><h2 id="🔑-關鍵技巧-主廚秘訣" tabindex="-1">🔑 關鍵技巧 / 主廚秘訣 <a class="header-anchor" href="#🔑-關鍵技巧-主廚秘訣" aria-label="Permalink to &quot;🔑 關鍵技巧 / 主廚秘訣&quot;">​</a></h2><ul><li><strong>泡菜要選熟的</strong>：熟成較久的酸泡菜煮鍋風味最佳</li><li><strong>番茄醬代替糖醋</strong>：平衡酸度、提鮮，讓湯頭更有層次</li><li><strong>水分兩次加</strong>：先加少量煮出濃郁底味，再加足湯量</li><li><strong>蒜末最後放</strong>：保留最鮮明的蒜香，是完美收尾的關鍵</li><li><strong>活用泡菜汁</strong>：用泡菜汁醃肉，讓肉從裡到外都有風味</li></ul><hr><h2 id="🍽️-推薦吃法" tabindex="-1">🍽️ 推薦吃法 <a class="header-anchor" href="#🍽️-推薦吃法" aria-label="Permalink to &quot;🍽️ 推薦吃法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>搭配</th><th>說明</th></tr></thead><tbody><tr><td>🍚 <strong>白飯</strong></td><td>韓式泡菜鍋最經典的搭配，湯汁拌飯超下飯</td></tr><tr><td>🥟 <strong>水餃</strong></td><td>變成泡菜餃子鍋，一鍋兩吃</td></tr><tr><td>🧀 <strong>起司片</strong></td><td>融化的起司讓湯頭更濃郁順口</td></tr><tr><td>🍜 <strong>泡麵</strong></td><td>最後加一份泡麵，吸滿湯汁超滿足</td></tr></tbody></table><hr><h2 id="📝-備註" tabindex="-1">📝 備註 <a class="header-anchor" href="#📝-備註" aria-label="Permalink to &quot;📝 備註&quot;">​</a></h2><ul><li>逐字稿無法取得，食譜內容根據影片標題、描述與時間軸整理</li><li>孫榮Kai Son（chefkaison）為五星級飯店主廚，擅長正統韓式料理</li><li>所有食材在台灣超市皆可買到</li></ul><hr><p><em>由 Hermes 於 2026/06/09 整理，依據孫榮Kai Son YouTube 影片</em></p>',42)])])}const b=r(n,[["render",d]]);export{u as __pageData,b as default};
